import machine
import time
from umqtt.simple import MQTTClient

# Set up Wi-Fi and MQTT broker connection
wlan = machine.WLAN(machine.STA_IF)
wlan.active(True)
wlan.connect('your_wifi_ssid', 'your_wifi_password')
time.sleep(5)

broker_ip = '192.168.1.100'  # Replace with your MQTT broker IP

client_id = b'sensor_001'
mqtt_client = MQTTClient(client_id, broker_ip)

# Set up temperature sensor
import onewire
from onewire import OneWire
ds_pin = machine.Pin(12)
ds_sensor = OneWire(ds_pin)
rom = ds_sensor.scan()[0]
temp_sensor = ds_sensor.temperature(rom)

while True:
    # Read temperature data
    temp_data = temp_sensor.read()
    
    # Publish temperature readings to MQTT broker
    mqtt_client.connect()
    mqtt_client.publish(b'sensors/temp', b'%d' % (temp_data * 100))
    mqtt_client.disconnect()

    time.sleep(10)